1	export type Customer = { yearsWithMHPCO: number };
2	export type Item = {
3	  type: string;
4	  material?: string;
5	  enchantment?: number;
6	  cursed?: boolean;
7	};
8	export type QuoteStep = { op: "quote"; items: Item[] };
9	export type Damage = { itemType: string; amount: number };
10	export type Incident = { cause: string; damages: Damage[] };
11	export type ClaimStep = { op: "claim"; policy: number; incident: Incident };
12	export type Step = QuoteStep | ClaimStep;
13	export type Scenario = { customer: Customer; steps: Step[] };
14	
15	export type QuoteResult = { premium: number };
16	export type ClaimResult = { payout: number; remainingCap: number };
17	export type StepResult = QuoteResult | ClaimResult;
18	export type ScenarioResult = { results: StepResult[] };
19	
20	export const runScenario = (_scenario: Scenario): ScenarioResult => {
21	  return { results: [{ premium: 5 }] };
